/**
 * ScannersPage — Unified scanner hub with all presets, signal counts,
 * and a global symbol search. Each preset card shows live match count.
 */
import { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { api } from '../utils/api';
import SymbolSearch from '../components/SymbolSearch';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { tokens } from '../styles/tokens';
import { SkeletonCardGrid } from '../components/SkeletonUI';
import s from './ScannersPage.module.css';

const C = {
  surface2: tokens.color.surfaceHover,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  textSec: tokens.color.textSecondary,
};

// Icons mapped by preset icon name
function PresetIcon({ name, color, size = 20 }) {
  const p = { width: size, height: size, stroke: color, strokeWidth: 2, fill: 'none' };
  switch (name) {
    case 'zap':
      return <svg viewBox="0 0 24 24" {...p}><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" /></svg>;
    case 'trending-up':
      return <svg viewBox="0 0 24 24" {...p}><polyline points="23 6 13.5 15.5 8.5 10.5 1 18" /><polyline points="17 6 23 6 23 12" /></svg>;
    case 'refresh-cw':
      return <svg viewBox="0 0 24 24" {...p}><polyline points="23 4 23 10 17 10" /><polyline points="1 20 1 14 7 14" /><path d="M3.51 9a9 9 0 0114.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0020.49 15" /></svg>;
    case 'bar-chart-2':
      return <svg viewBox="0 0 24 24" {...p}><line x1="18" y1="20" x2="18" y2="10" /><line x1="12" y1="20" x2="12" y2="4" /><line x1="6" y1="20" x2="6" y2="14" /></svg>;
    case 'arrow-up-circle':
      return <svg viewBox="0 0 24 24" {...p}><circle cx="12" cy="12" r="10" /><polyline points="16 12 12 8 8 12" /><line x1="12" y1="16" x2="12" y2="8" /></svg>;
    case 'arrow-down-circle':
      return <svg viewBox="0 0 24 24" {...p}><circle cx="12" cy="12" r="10" /><polyline points="8 12 12 16 16 12" /><line x1="12" y1="8" x2="12" y2="16" /></svg>;
    case 'trending-down':
      return <svg viewBox="0 0 24 24" {...p}><polyline points="23 18 13.5 8.5 8.5 13.5 1 6" /><polyline points="17 18 23 18 23 12" /></svg>;
    case 'dollar-sign':
      return <svg viewBox="0 0 24 24" {...p}><line x1="12" y1="1" x2="12" y2="23" /><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6" /></svg>;
    case 'target':
      return <svg viewBox="0 0 24 24" {...p}><circle cx="12" cy="12" r="10" /><circle cx="12" cy="12" r="6" /><circle cx="12" cy="12" r="2" /></svg>;
    default:
      return <svg viewBox="0 0 24 24" {...p}><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>;
  }
}

// Route mapping for each preset key
const PRESET_ROUTES = {
  momentum_breakout: '/scanners/momentum',
  oversold_bounce: '/scanners/reversals',
  reversal_plays: '/scanners/reversals',
  volume_spike: '/scanners/volume',
  new_highs: '/scanners/momentum',
  new_lows: '/scanners/momentum',
  short_setups: '/scanners/momentum',
  earnings_movers: '/scanners/momentum',
  high_conviction: '/scanners/momentum',
};

export default function ScannersPage() {
  usePageTitle('Scanners');
  const navigate = useNavigate();
  const isMobile = useIsMobile();
  const [presets, setPresets] = useState({});
  const [loading, setLoading] = useState(true);
  const [liveSignals, setLiveSignals] = useState(null);

  const fetchPresets = useCallback(async () => {
    setLoading(true);
    try {
      const [scanData, liveData] = await Promise.all([
        api('/scanners'),
        api('/scanners/signals/live'),
      ]);
      if (scanData?.presets) {
        setPresets(typeof scanData.presets === 'object' && !Array.isArray(scanData.presets)
          ? scanData.presets
          : {}
        );
      }
      if (liveData) {
        setLiveSignals(liveData);
      }
    } catch {
      // silent
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchPresets();
    const iv = setInterval(fetchPresets, 30000);
    return () => clearInterval(iv);
  }, [fetchPresets]);

  const presetList = useMemo(() =>
    Object.entries(presets).map(([key, val]) => ({
      key,
      name: val.name || key,
      description: val.description || '',
      icon: val.icon || 'search',
      color: val.color || C.blue,
      signalCount: val.signal_count ?? 0,
      strategies: val.strategies || [],
    })),
    [presets]
  );

  const totalSignals = liveSignals?.total_signals ?? presetList.reduce((sum, p) => sum + p.signalCount, 0);

  const handlePresetClick = (key) => {
    const route = PRESET_ROUTES[key] || '/scanners/momentum';
    navigate(route);
  };

  const handleSymbolSelect = (symbol) => {
    navigate(`/charts?symbol=${encodeURIComponent(symbol)}`);
  };

  return (
    <div className={s.page} style={{ padding: isMobile ? '16px' : '24px 32px' }}>
      {/* Header */}
      <div className={s.header}>
        <h1 className={`${s.title} ${isMobile ? s.titleMobile : ''}`}>
          Scanners
        </h1>
        <p className={s.subtitle}>
          Pre-built strategy scanners with real-time signal detection
        </p>
      </div>

      {/* Symbol Search Bar */}
      <div className={s.searchWrap}>
        <SymbolSearch
          onSelect={handleSymbolSelect}
          placeholder="Quick search: symbol, company name..."
        />
      </div>

      {/* Live signal stats */}
      <div className={`${s.statsGrid} ${isMobile ? s.statsGridMobile : ''}`}>
        <StatBox label="Total Signals" value={totalSignals} color={C.green} />
        <StatBox label="Live Signals" value={liveSignals?.live_signals ?? '--'} color={C.blue} />
        <StatBox label="Scanner Presets" value={presetList.length} color={C.amber} />
        <StatBox
          label="Signal Freshness"
          value={liveSignals?.status === 'current' ? 'Current' : liveSignals?.status === 'stale' ? 'Stale' : '--'}
          color={liveSignals?.status === 'current' ? C.green : C.amber}
        />
      </div>

      {/* Loading */}
      {loading && (
        <SkeletonCardGrid count={9} columns="repeat(auto-fill, minmax(300px, 1fr))" />
      )}

      {/* Preset Cards Grid */}
      {!loading && (
        <div className={`${s.presetsGrid} ${isMobile ? s.presetsGridMobile : ''}`}>
          {presetList.map((preset, i) => (
            <motion.div
              key={preset.key}
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.2, delay: i * 0.04 }}
              onClick={() => handlePresetClick(preset.key)}
              className={s.presetCard}
              whileHover={{ scale: 1.02, borderColor: preset.color }}
              whileTap={{ scale: 0.98 }}
            >
              {/* Color accent bar */}
              <div className={s.accentBar} style={{ background: preset.color }} />

              <div className={s.presetTop}>
                <div className={s.presetLeft}>
                  <div className={s.presetIconBox} style={{ background: preset.color + '18' }}>
                    <PresetIcon name={preset.icon} color={preset.color} size={18} />
                  </div>
                  <div>
                    <div className={s.presetName}>{preset.name}</div>
                  </div>
                </div>
                {/* Signal count badge */}
                <div className={s.signalBadge} style={{
                  background: preset.signalCount > 0 ? preset.color + '22' : C.surface2,
                  color: preset.signalCount > 0 ? preset.color : C.textSec,
                }}>
                  {preset.signalCount}
                </div>
              </div>

              <div className={s.presetDesc}>
                {preset.description}
              </div>

              <div className={s.stratTags}>
                {preset.strategies.slice(0, 3).map((strat) => (
                  <span key={strat} className={s.stratTag}>
                    {strat.replace(/_/g, ' ')}
                  </span>
                ))}
                {preset.strategies.length > 3 && (
                  <span className={s.stratTag}>
                    +{preset.strategies.length - 3} more
                  </span>
                )}
              </div>
            </motion.div>
          ))}
        </div>
      )}

      {/* Live Signals by Strategy */}
      {liveSignals?.signals?.length > 0 && (
        <div className={s.liveSection}>
          <h2 className={s.liveTitle}>
            Live Signals by Strategy
          </h2>
          <div className={s.tableWrap}>
            <table className={s.table}>
              <thead className={s.thead}>
                <tr>
                  <th className={`${s.th} ${s.thLeft}`}>Strategy</th>
                  <th className={`${s.th} ${s.thRight}`}>Signal Count</th>
                  <th className={`${s.th} ${s.thLeft}`}>Strength</th>
                </tr>
              </thead>
              <tbody>
                {liveSignals.signals.slice(0, 20).map((sig, i) => (
                  <tr key={sig.strategy || i} style={{
                    borderBottom: i < liveSignals.signals.length - 1 ? undefined : 'none',
                  }}>
                    <td className={`${s.td} ${s.tdStrategy}`}>
                      {(sig.strategy || '--').replace(/_/g, ' ')}
                    </td>
                    <td className={`${s.td} ${s.tdCount}`}>
                      {sig.count}
                    </td>
                    <td className={s.td}>
                      <div className={s.strengthBar}>
                        <div className={s.strengthTrack}>
                          <div className={s.strengthFill} style={{
                            width: `${Math.min(100, (sig.count / Math.max(1, liveSignals.signals[0]?.count || 1)) * 100)}%`,
                            background: sig.count > 5 ? C.green : sig.count > 2 ? C.amber : C.textSec,
                          }} />
                        </div>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

function StatBox({ label, value, color }) {
  return (
    <div className={s.statBox}>
      <div className={s.statLabel}>{label}</div>
      <div className={s.statValue} style={{ color }}>{value}</div>
    </div>
  );
}
